mapper.select:
SELECT id, user_id, title, last_question, transfer_suggested, created_at, updated_at
FROM ai_session
WHERE id = #{sessionId}
  AND user_id = #{userId}

SELECT id, session_id, user_id, role, content, model_name, can_answer,
       confidence, transfer_suggested, transfer_reason, created_at
FROM ai_message
WHERE id = #{messageId}
  AND session_id = #{sessionId}
  AND user_id = #{userId}
  AND role = 'ASSISTANT'

